// TC-042: Edge stroke and arrowhead fill meet WCAG 3:1 non-text contrast in
// both light and dark mode. Regression guard for the border-line→fg-muted
// token swap on D3Graph edges.
test('TC-042: doc graph edges meet >=3:1 contrast in light and dark mode', async ({ page }) => {
	await mockGraphQL(page);
	await page.goto(BASE_URL);

	const svg = page.getByTestId('doc-graph-svg');
	await expect(svg).toBeVisible();
	await page.waitForFunction(
		() => document.querySelectorAll('[data-testid="doc-graph-svg"] line').length > 0
	);

	// Pull computed colors out of the live DOM, blend stroke against the
	// nearest opaque ancestor background, and compute the WCAG contrast ratio.
	const measure = () =>
		page.evaluate(() => {
			function parseRgb(s: string): [number, number, number, number] {
				const m = s.match(/rgba?\(([^)]+)\)/i);
				if (!m) return [0, 0, 0, 1];
				const parts = m[1].split(',').map((p) => parseFloat(p.trim()));
				return [parts[0], parts[1], parts[2], parts[3] === undefined ? 1 : parts[3]];
			}
			function effectiveBg(el: Element): [number, number, number] {
				let cur: Element | null = el;
				while (cur) {
					const cs = getComputedStyle(cur);
					const [r, g, b, a] = parseRgb(cs.backgroundColor);
					if (a > 0) return [r, g, b];
					cur = cur.parentElement;
				}
				return [255, 255, 255];
			}
			function blend(
				fg: [number, number, number],
				alpha: number,
				bg: [number, number, number]
			): [number, number, number] {
				return [
					fg[0] * alpha + bg[0] * (1 - alpha),
					fg[1] * alpha + bg[1] * (1 - alpha),
					fg[2] * alpha + bg[2] * (1 - alpha)
				];
			}
			function chan(c: number) {
				const v = c / 255;
				return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
			}
			function lum([r, g, b]: [number, number, number]) {
				return 0.2126 * chan(r) + 0.7152 * chan(g) + 0.0722 * chan(b);
			}
			function contrast(a: [number, number, number], b: [number, number, number]) {
				const la = lum(a);
				const lb = lum(b);
				const [hi, lo] = la > lb ? [la, lb] : [lb, la];
				return (hi + 0.05) / (lo + 0.05);
			}

			const line = document.querySelector(
				'[data-testid="doc-graph-svg"] line'
			) as SVGLineElement | null;
			const arrow = document.querySelector(
				'[data-testid="doc-graph-svg"] marker#ddx-arrow path'
			) as SVGPathElement | null;
			if (!line || !arrow) throw new Error('graph edge or arrowhead not found');

			const lineCs = getComputedStyle(line);
			const arrowCs = getComputedStyle(arrow);
			const stroke = parseRgb(lineCs.stroke);
			const strokeOpacity = parseFloat(lineCs.strokeOpacity || '1');
			const fill = parseRgb(arrowCs.fill);
			const bg = effectiveBg(line);

			const blendedStroke = blend([stroke[0], stroke[1], stroke[2]], strokeOpacity, bg);
			return {
				stroke: contrast(blendedStroke, bg),
				arrow: contrast([fill[0], fill[1], fill[2]], bg)
			};
		});

	const html = page.locator('html');
	const initialClass = (await html.getAttribute('class')) ?? '';
	const startedDark = initialClass.includes('dark');
	const toggle = page.getByRole('button', { name: /toggle dark mode/i });

	// Ensure we start in light mode.
	if (startedDark) {
		await toggle.click();
		await expect(html).not.toHaveClass(/dark/);
	}

	const lightRatios = await measure();
	expect(lightRatios.stroke).toBeGreaterThanOrEqual(3);
	expect(lightRatios.arrow).toBeGreaterThanOrEqual(3);

	await toggle.click();
	await expect(html).toHaveClass(/dark/);

	const darkRatios = await measure();
	expect(darkRatios.stroke).toBeGreaterThanOrEqual(3);
	expect(darkRatios.arrow).toBeGreaterThanOrEqual(3);
});

